def get_instr_attr(instr, attr, default=None):
    """统一获取指令属性，支持字典和对象"""
    if isinstance(instr, dict):
        return instr.get(attr, default)
    elif hasattr(instr, attr):
        return getattr(instr, attr)
    return default

